#!/bin/bash
set -euo pipefail
NAME=${1:?Usage: create-pvc.sh <name> <size> [storage-class] [access-mode]}
SIZE=${2:?Usage: create-pvc.sh <name> <size> [storage-class] [access-mode]}
SC=${3:-standard}
ACCESS=${4:-ReadWriteOnce}
NS=${KUBE_NAMESPACE:-default}

cat <<EOF | kubectl apply -f -
apiVersion: v1
kind: PersistentVolumeClaim
metadata:
  name: ${NAME}
  namespace: ${NS}
spec:
  accessModes:
    - ${ACCESS}
  resources:
    requests:
      storage: ${SIZE}
  storageClassName: ${SC}
EOF

echo "PVC $NAME created in namespace $NS:"
kubectl get pvc "$NAME" -n "$NS"
